```go
type StatusError struct{ Code int }
func (e StatusError) Error() string { return fmt.Sprintf("status %d", e.Code) }
func (e StatusError) Is(target error) bool {
	t, ok := target.(StatusError); return ok && t.Code == e.Code
}
